#include <bits/stdc++.h>
using namespace std;

int t, w;
int a[1005], f[1005][2][35];
int ans = 0;

int DFS(int x, bool p, int s) {
    if (x == t) return (f[x][p][s] = 0);
    if (f[x][p][s] != -1) return f[x][p][s];
    int maxn = 0;
    if (s < w) {
        maxn = DFS(x + 1, !p, s + 1);
    }
    maxn = max(maxn, DFS(x + 1, p, s));
    if (a[x] == p) maxn++;
    f[x][p][s] = maxn;
    return maxn;
}

int main() {
    memset(f, -1, sizeof(f));
    cin >> t >> w;
    for (int i = 0; i < t; i++) {
        cin >> a[i];
        a[i]--;
    }
    cout << DFS(0, 0, 0) << endl;
    return 0;
}
